import{_ as e,o as i,c as l,a5 as t}from"./chunks/framework.D9Kapg2s.js";const p=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/faq.md","filePath":"zh/guide/faq.md"}'),o={name:"zh/guide/faq.md"};function r(s,a,h,d,n,c){return i(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="安装与启动" tabindex="-1">安装与启动 <a class="header-anchor" href="#安装与启动" aria-label="Permalink to &quot;安装与启动&quot;">​</a></h2><h3 id="docker-启动后无法访问" tabindex="-1">Docker 启动后无法访问？ <a class="header-anchor" href="#docker-启动后无法访问" aria-label="Permalink to &quot;Docker 启动后无法访问？&quot;">​</a></h3><p>检查端口映射是否正确：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 确认容器正在运行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linguaflow</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 查看日志</span></span></code></pre></div><p>确保端口未被占用，并检查防火墙设置。</p><h3 id="从源码构建失败" tabindex="-1">从源码构建失败？ <a class="header-anchor" href="#从源码构建失败" aria-label="Permalink to &quot;从源码构建失败？&quot;">​</a></h3><ol><li>确认 Go 版本 &gt;= 1.21</li><li>确认 Node.js 版本 &gt;= 20</li><li>确认已安装 pnpm</li><li>运行 <code>task backend:install</code> 和 <code>task frontend:install</code> 安装依赖</li></ol><h2 id="ai-后端配置" tabindex="-1">AI 后端配置 <a class="header-anchor" href="#ai-后端配置" aria-label="Permalink to &quot;AI 后端配置&quot;">​</a></h2><h3 id="api-key-无效" tabindex="-1">API Key 无效？ <a class="header-anchor" href="#api-key-无效" aria-label="Permalink to &quot;API Key 无效？&quot;">​</a></h3><ul><li>确认 API Key 是否正确复制（无多余空格）</li><li>确认 API Key 是否有效（未过期、未被禁用）</li><li>检查 Base URL 是否正确（如果使用了自定义代理）</li></ul><h3 id="翻译速度很慢" tabindex="-1">翻译速度很慢？ <a class="header-anchor" href="#翻译速度很慢" aria-label="Permalink to &quot;翻译速度很慢？&quot;">​</a></h3><ul><li>检查网络连接到 AI 服务的速度</li><li>尝试使用不同的 AI 模型（较小的模型通常更快）</li><li>减少上下文窗口大小</li><li>检查是否有速率限制</li></ul><h3 id="翻译质量不理想" tabindex="-1">翻译质量不理想？ <a class="header-anchor" href="#翻译质量不理想" aria-label="Permalink to &quot;翻译质量不理想？&quot;">​</a></h3><ul><li>使用术语表确保术语一致性</li><li>自定义提示词模板</li><li>提供更多上下文信息</li><li>尝试不同的 AI 模型</li><li>使用多轮翻译流水线</li><li>启用质量检测 + AI 质量裁决，先降噪再人工审校</li></ul><h3 id="兼容网关要求-stream-true" tabindex="-1">兼容网关要求 stream:true？ <a class="header-anchor" href="#兼容网关要求-stream-true" aria-label="Permalink to &quot;兼容网关要求 stream:true？&quot;">​</a></h3><p>在 AI 后端选项中开启 <strong>流式请求</strong>（<code>stream: true</code>）。请求以流式发起，服务端内部累积为完整响应后再处理，对外行为不变。OpenAI / Anthropic / Google 三类后端均支持。</p><h3 id="源语残留误报很多" tabindex="-1">源语残留误报很多？ <a class="header-anchor" href="#源语残留误报很多" aria-label="Permalink to &quot;源语残留误报很多？&quot;">​</a></h3><p>源语残留检测偏敏感（专有名词、代码、刻意保留原文等可能被标出）。可：</p><ol><li>在执行计划中增加 <strong>质量裁决</strong>（<code>adjudicate</code>）轮次，对 <code>source_residual</code> 做 AI 复核</li><li>在段落列表中按 <code>source_residual</code> 筛选后人工确认</li><li>确保项目源语言不是 <code>auto</code>（<code>auto</code> 时残留检测不生效，但指定错误语言也会影响规则）</li></ol><h2 id="文件格式" tabindex="-1">文件格式 <a class="header-anchor" href="#文件格式" aria-label="Permalink to &quot;文件格式&quot;">​</a></h2><h3 id="支持哪些格式" tabindex="-1">支持哪些格式？ <a class="header-anchor" href="#支持哪些格式" aria-label="Permalink to &quot;支持哪些格式？&quot;">​</a></h3><p>Markdown、HTML、DOCX、EPUB、SRT/VTT/ASS 字幕、JSON/YAML/TOML、纯文本等。详见 <a href="/zh/guide/formats.html">格式支持</a>。</p><h3 id="epub-翻译后排版混乱" tabindex="-1">EPUB 翻译后排版混乱？ <a class="header-anchor" href="#epub-翻译后排版混乱" aria-label="Permalink to &quot;EPUB 翻译后排版混乱？&quot;">​</a></h3><ul><li>确认 EPUB 文件格式是否标准</li><li>尝试按章节分批翻译</li><li>检查是否有特殊格式需要保护</li></ul><h3 id="docx-部分内容未翻译" tabindex="-1">DOCX 部分内容未翻译？ <a class="header-anchor" href="#docx-部分内容未翻译" aria-label="Permalink to &quot;DOCX 部分内容未翻译？&quot;">​</a></h3><p>当前主要处理主文档 <code>word/document.xml</code> 中的段落。页眉页脚、批注、SmartArt、图表等可能不在翻译范围内，翻译后请用 Word 打开校对。</p><h3 id="字幕文件时间码被修改" tabindex="-1">字幕文件时间码被修改？ <a class="header-anchor" href="#字幕文件时间码被修改" aria-label="Permalink to &quot;字幕文件时间码被修改？&quot;">​</a></h3><p>LinguaFlow 会自动保护时间码，如果发现时间码被修改：</p><ul><li>检查文件编码是否为 UTF-8</li><li>确认文件格式是否正确</li></ul><h2 id="数据与存储" tabindex="-1">数据与存储 <a class="header-anchor" href="#数据与存储" aria-label="Permalink to &quot;数据与存储&quot;">​</a></h2><h3 id="数据存储在哪里" tabindex="-1">数据存储在哪里？ <a class="header-anchor" href="#数据存储在哪里" aria-label="Permalink to &quot;数据存储在哪里？&quot;">​</a></h3><ul><li><strong>本地模式</strong> — SQLite，默认在系统用户配置目录下的 <code>LinguaFlow</code>（如 Windows <code>%APPDATA%\\LinguaFlow</code>）</li><li><strong>服务器模式</strong> — 默认 <code>./data/linguaflow.db</code>；可用 <code>--data-dir</code> 或环境变量指定；PostgreSQL 时数据在数据库中，但任务/资源相关本地文件仍在默认或者指定的服务端本地数据根目录下</li></ul><h3 id="如何备份数据" tabindex="-1">如何备份数据？ <a class="header-anchor" href="#如何备份数据" aria-label="Permalink to &quot;如何备份数据？&quot;">​</a></h3><p>复制 SQLite 数据库文件即可：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/linguaflow.db</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./backup/linguaflow_backup.db</span></span></code></pre></div><h3 id="如何迁移数据" tabindex="-1">如何迁移数据？ <a class="header-anchor" href="#如何迁移数据" aria-label="Permalink to &quot;如何迁移数据？&quot;">​</a></h3><p>将数据库文件复制到新环境即可。</p><h2 id="性能与限制" tabindex="-1">性能与限制 <a class="header-anchor" href="#性能与限制" aria-label="Permalink to &quot;性能与限制&quot;">​</a></h2><h3 id="支持多大的文件" tabindex="-1">支持多大的文件？ <a class="header-anchor" href="#支持多大的文件" aria-label="Permalink to &quot;支持多大的文件？&quot;">​</a></h3><p>文件大小限制取决于：</p><ul><li>AI 服务的上下文窗口大小</li><li>可用内存</li><li>网络带宽</li></ul><p>建议大文件按章节或段落分批翻译。</p><h3 id="支持多少并发翻译" tabindex="-1">支持多少并发翻译？ <a class="header-anchor" href="#支持多少并发翻译" aria-label="Permalink to &quot;支持多少并发翻译？&quot;">​</a></h3><p>并发数取决于：</p><ul><li>AI 服务的速率限制</li><li>系统资源</li><li>配置的并发数设置</li></ul><h2 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h2><p>如果以上内容没有解决您的问题：</p><ul><li>查看 <a href="https://github.com/MeowSalty/LinguaFlow/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 寻找类似问题</li><li><a href="https://github.com/MeowSalty/LinguaFlow/issues/new" target="_blank" rel="noreferrer">提交新 Issue</a> 描述您的问题</li></ul>`,49)])])}const k=e(o,[["render",r]]);export{p as __pageData,k as default};
